mapper.select:
SELECT entry_id, category, title, content, status, created_by, reviewed_by, effective_at, created_at, updated_at FROM t_knowledge_entry
AND category = #{category}
ORDER BY updated_at DESC

mapper.update:
UPDATE t_knowledge_entry
SET status = #{status}, updated_at = NOW()
WHERE entry_id = #{entryId}

UPDATE t_knowledge_entry
SET category = #{category}, title = #{title}, content = #{content}, updated_at = #{updatedAt}
WHERE entry_id = #{entryId}
